lib/bundles.cf  Table of contents file bodies control Prototype: control Description: Include policy files used by this policy file as part of inputs Implementation: code body file control { inputs =&gt; { @(bundles_common.inputs) }; } common bodies bundles_common Prototype: bundles_common Description: Enumerate policy files used by this policy file for inclusion to inputs Implementation: code bundle common bundles_common { vars : &quot; inputs &quot; slist =&gt; { &quot; $(this.promise_dirname) /paths.cf&quot; , &quot; $(this.promise_dirname) /files.cf&quot; , &quot; $(this.promise_dirname) /commands.cf&quot; }; } agent bundles cronjob Prototype: cronjob(commands, user, hours, mins) Description: Defines a cron job for user Adds a line to crontab, if necessary. Arguments: commands : The commands that should be run user : The owner of crontab hours : The hours at which the job should run mins : The minutes at which the job should run Example: code methods : &quot;cron&quot; usebundle =&gt; cronjob ( &quot;/bin/ls&quot; , &quot;mark&quot; , &quot;*&quot; , &quot;5,10&quot; ); Implementation: code bundle agent cronjob ( commands , user , hours , mins ) { vars : suse|sles :: &quot; crontab &quot; string =&gt; &quot;/var/spool/cron/tabs&quot; ; redhat|fedora :: &quot; crontab &quot; string =&gt; &quot;/var/spool/cron&quot; ; freebsd :: &quot; crontab &quot; string =&gt; &quot;/var/cron/tabs&quot; ; !(suse|sles|redhat|fedora|freebsd) :: &quot; crontab &quot; string =&gt; &quot;/var/spool/cron/crontabs&quot; ; any :: # We escape the user supplied values so that we can search to see if the # entry already exists with slightly different spacing. &quot; e_mins &quot; string =&gt; escape ( &quot; $(mins) &quot; ); &quot; e_hours &quot; string =&gt; escape ( &quot; $(hours) &quot; ); &quot; e_commands &quot; string =&gt; escape ( &quot; $(commands) &quot; ); classes : !windows :: # We tolerate existing entries that differ only in whitespace and avoid # entering duplicate entries. &quot;present_with_potentially_different_spacing&quot; expression =&gt; regline ( &quot;^ $(e_mins) \s + $(e_hours) \s + \*\s + \*\s + \*\s + $(e_commands) &quot; , &quot; $(crontab) / $(user) &quot; ), if =&gt; fileexists ( &quot; $(crontab) / $(user) &quot; ); files : !windows.!present_with_potentially_different_spacing :: &quot; $(crontab) / $(user) &quot; comment =&gt; &quot;A user&#39;s regular batch jobs are added to this file&quot; , create =&gt; &quot;true&quot; , edit_line =&gt; append_if_no_line ( &quot; $(mins) $(hours) * * * $(commands) &quot; ), perms =&gt; mo ( &quot;600&quot; , &quot; $(user) &quot; ), classes =&gt; if_repaired ( &quot;changed_crontab&quot; ); processes : changed_crontab :: &quot;cron&quot; comment =&gt; &quot;Most crons need to be huped after file changes&quot; , signals =&gt; { &quot;hup&quot; }; } rm_rf Prototype: rm_rf(name) Description: recursively remove name to any depth, including base Arguments: name : the file or directory name This bundle will remove name to any depth, including name itself. Example: code methods : &quot;bye&quot; usebundle =&gt; rm_rf ( &quot;/var/tmp/oldstuff&quot; ); Implementation: code bundle agent rm_rf ( name ) { methods : &quot;rm&quot; usebundle =&gt; rm_rf_depth ( $ ( name ), &quot;inf&quot; ); } rm_rf_depth Prototype: rm_rf_depth(name, depth) Description: recursively remove name to depth depth , including base Arguments: name : the file or directory name depth : how far to descend This bundle will remove name to depth depth , including name itself. Example: code methods : &quot;bye&quot; usebundle =&gt; rm_rf_depth ( &quot;/var/tmp/oldstuff&quot; , &quot;100&quot; ); Implementation: code bundle agent rm_rf_depth ( name , depth ) { classes : &quot;isdir&quot; expression =&gt; isdir ( $ ( name )); files : isdir :: &quot; $(name) &quot; file_select =&gt; all , depth_search =&gt; recurse_with_base ( $ ( depth )), delete =&gt; tidy ; &quot; $(name) /.&quot; delete =&gt; tidy ; !isdir :: &quot; $(name) &quot; delete =&gt; tidy ; } fileinfo Prototype: fileinfo(f) Description: provide access to file stat fields from the bundle caller and report file stat info for file &quot;f&quot; if &quot;verbose_mode&quot; class is defined Arguments: f : file or files to stat Example: code bundle agent example { vars : &quot; files &quot; slist =&gt; { &quot;/tmp/example1&quot; , &quot;/tmp/example2&quot; }; files : &quot; $(files) &quot; create =&gt; &quot;true&quot; , classes =&gt; if_ok ( &quot;verbose_mode&quot; ), comment =&gt; &quot;verbose_mode is defined because the fileinfo bundle restricts the report of the file info to verbose mode&quot; ; &quot;/tmp/example3&quot; create =&gt; &quot;true&quot; , classes =&gt; if_ok ( &quot;verbose_mode&quot; ), comment =&gt; &quot;verbose_mode is defined because the fileinfo bundle restricts the report of the file info to verbose mode&quot; ; methods : &quot;fileinfo&quot; usebundle =&gt; fileinfo ( @(files) ); &quot;fileinfo&quot; usebundle =&gt; fileinfo ( &quot;/tmp/example3&quot; ); reports : &quot; $(this.bundle) : $(files) : $(fileinfo.fields) = &#39; $(fileinfo.stat[$(files)][$(fileinfo.fields)]) &#39;&quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][size]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][gid]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][uid]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][ino]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][nlink]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][ctime]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][atime]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][mtime]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][mode]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][modeoct]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][permstr]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][permoct]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][type]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][devno]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][dev_minor]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][dev_major]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][basename]) &quot; ; &quot; $(this.bundle) : $(fileinfo.stat[/tmp/example3][dirname]) &quot; ; } Implementation: code bundle agent fileinfo ( f ) { vars : &quot; fields &quot; slist =&gt; splitstring ( &quot;size,gid,uid,ino,nlink,ctime,atime,mtime,mode,modeoct,permstr,permoct,type,devno,dev_minor,dev_major,basename,dirname,linktarget,linktarget_shallow&quot; , &quot;,&quot; , 999 ); &quot; stat[$(f)][$(fields)] &quot; string =&gt; filestat ( $ ( f ), $ ( fields )); reports : verbose_mode :: &quot; $(this.bundle) : file $(f) has $(fields) = $(stat[$(f)][$(fields)]) &quot; ; } logrotate Prototype: logrotate(log_files, max_size, rotate_levels) Description: rotate specified &quot;log_files&quot; larger than &quot;max_size&quot;. Keep &quot;rotate_levels&quot; versions of the files before overwriting the oldest one Arguments: log_files : single file or list of files to evaluate for rotation max_size : minimum size in bytes that the file will grow to before being rotated rotate_levels : number of rotations to keep before overwriting the oldest one Example: code bundle agent example { vars : &quot; logdirs &quot; slist =&gt; { &quot;/var/log/syslog&quot; , &quot;/var/log/maillog&quot; }; methods : &quot;logrotate&quot; usebundle =&gt; logrotate ( @(logdirs) , &quot;1M&quot; , &quot;2&quot; ); &quot;logrotate&quot; usebundle =&gt; logrotate ( &quot;/var/log/mylog, &quot; 1 &quot;, &quot; 5 &quot; ); &quot; logrotate &quot; usebundle =&gt; logrotate( &quot; / var / log / alog , &quot;500k&quot; , &quot;7&quot; ); } Implementation: code bundle agent logrotate ( log_files , max_size , rotate_levels ) { files : &quot; $(log_files) &quot; comment =&gt; &quot;Rotate file if above specified size&quot; , rename =&gt; rotate ( &quot; $(rotate_levels) &quot; ), file_select =&gt; bigger_than ( &quot; $(max_size) &quot; ), if =&gt; fileexists ( $ ( log_files ) ); } prunedir Prototype: prunedir(dir, max_days) Description: delete plain files inside &quot;dir&quot; older than &quot;max_days&quot; (not recursively). Arguments: dir : directory to examine for files max_days : maximum number of days old a files mtime is allowed to before deletion Example: code bundle agent example { vars : &quot; dirs &quot; slist =&gt; { &quot;/tmp/logs&quot; , &quot;/tmp/logs2&quot; }; methods : &quot;prunedir&quot; usebundle =&gt; prunedir ( @(dirs) , &quot;1&quot; ); } Implementation: code bundle agent prunedir ( dir , max_days ) { files : &quot; $(dir) &quot; comment =&gt; &quot;Delete plain files inside directory older than max_days&quot; , delete =&gt; tidy , file_select =&gt; filetype_older_than ( &quot;plain&quot; , &quot; $(max_days) &quot; ), depth_search =&gt; recurse ( &quot;1&quot; ); } prunetree Prototype: prunetree(dir, depth, max_days) Description: Delete files and directories inside &quot;dir&quot; up to &quot;depth&quot; older than &quot;max_days&quot;. Arguments: dir : directory to examine for files depth : How many levels to descend max_days : maximum number of days old a files mtime is allowed to before deletion Example: code bundle agent example { vars : &quot; dirs &quot; slist =&gt; { &quot;/tmp/logs&quot; , &quot;/tmp/logs2&quot; }; methods : &quot;prunetree&quot; usebundle =&gt; prunetree ( @(dirs) , inf , &quot;1&quot; ); } Implementation: code bundle agent prunetree ( dir , depth , max_days ) { files : &quot; $(dir) &quot; comment =&gt; &quot;Delete files and directories under $(dir) up to $(depth) depth older than $(max_days) &quot; , delete =&gt; tidy , file_select =&gt; days_old ( $ ( max_days ) ), depth_search =&gt; recurse_with_base ( $ ( depth ) ); } url_ping Prototype: url_ping(host, method, port, uri) Description: ping HOST:PORT/URI using METHOD Arguments: host : the host name method : the HTTP method (HEAD or GET) port : the port number, e.g. 80 uri : the URI, e.g. /path/to/resource This bundle will send a simple HTTP request and read 20 bytes back, then compare them to 200 OK.* (ignoring leading spaces). If the data matches, the global class &quot;url_ok_HOST&quot; will be set, where HOST is the canonified host name, i.e. canonify($(host)) Example: code methods : &quot;check&quot; usebundle =&gt; url_ping ( &quot;cfengine.com&quot; , &quot;HEAD&quot; , &quot;80&quot; , &quot;/bill/was/here&quot; ); reports : url_ok_cfengine_com :: &quot;CFEngine&#39;s web site is up&quot; ; url_not_ok_cfengine_com :: &quot;CFEngine&#39;s web site *may* be down. Or you&#39;re offline.&quot; ; Implementation: code bundle agent url_ping ( host , method , port , uri ) { vars : &quot; url_check &quot; string =&gt; readtcp ( $ ( host ), $ ( port ), &quot; $(method) $(uri) HTTP/1.1 $(const.r)$(const.n) Host: $(host)$(const.r)$(const.n)$(const.r)$(const.n) &quot; , 20 ); &quot; chost &quot; string =&gt; canonify ( $ ( host )); classes : &quot;url_ok_ $(chost) &quot; scope =&gt; &quot;namespace&quot; , expression =&gt; regcmp ( &quot;[^ 
]*200 OK.* 
.*&quot; , $ ( url_check )); &quot;url_not_ok_ $(chost) &quot; scope =&gt; &quot;namespace&quot; , not =&gt; regcmp ( &quot;[^ 
]*200 OK.* 
.*&quot; , $ ( url_check )); reports : verbose_mode :: &quot; $(this.bundle) : $(method) $(host) : $(port) / $(uri) got 200 OK&quot; if =&gt; &quot;url_ok_ $(chost) &quot; ; &quot; $(this.bundle) : $(method) $(host) : $(port) / $(uri) did *not* get 200 OK&quot; if =&gt; &quot;url_not_ok_ $(chost) &quot; ; } cmerge Prototype: cmerge(name, varlist) Description: bundle to merge many data containers into one Arguments: name : the variable name to create varlist : a list of variable names (**MUST** be a list) The result will be in cmerge.$(name) . You can also use cmerge.$(name)_str for a string version of the merged containers. The name is variable so you can call this bundle for more than one merge. If you merge a key-value map into an array or vice versa, the map always wins. So this example will result in a key-value map even though cmerge.$(name) starts as an array. Example: code bundle agent run { vars : # the &quot;mymerge&quot; tag is user-defined &quot;a&quot; data =&gt; parsejson ( &#39; { &quot;mark&quot; : &quot;b&quot; } &#39; ), meta =&gt; { &quot;mymerge&quot; }; &quot;b&quot; data =&gt; parsejson ( &#39; { &quot;volker&quot; : &quot;h&quot; } &#39; ), meta =&gt; { &quot;mymerge&quot; }; # you can list them explicitly: &quot;default:run.a&quot; through &quot;default:run.d&quot; &quot; todo &quot; slist =&gt; variablesmatching ( &quot;.*&quot; , &quot;mymerge&quot; ); # you can use cmerge.all_str instead of accessing the merged data directly &quot; merged_str &quot; string =&gt; format ( &quot;%S&quot; , &quot;cmerge.all&quot; ); methods : &quot;go&quot; usebundle =&gt; cmerge ( &quot;all&quot; , @(todo) ); # merge a, b into container cmerge.all reports : &quot;merged = $(cmerge.all_str) &quot; ; # will print a map with keys &quot;mark&quot; and &quot;volker&quot; } Implementation: code bundle agent cmerge ( name , varlist ) { vars : &quot; $(name) &quot; data =&gt; parsejson ( &#39;[]&#39; ), policy =&gt; &quot;free&quot; ; &quot; $(name) &quot; data =&gt; mergedata ( $ ( name ), $ ( varlist )), policy =&gt; &quot;free&quot; ; # iterates! &quot; $(name)_str &quot; string =&gt; format ( &quot;%S&quot; , $ ( name )), policy =&gt; &quot;free&quot; ; } collect_vars Prototype: collect_vars(name, tag, flatten) Description: bundle to collect tagged variables into a data container Arguments: name : the variable name to create inside collect_vars tag : the tag regex string to match e.g. &quot;beta,gamma=.*&quot; flatten : to flatten variable values, set to &quot;any&quot; or &quot;true&quot; or &quot;1&quot; The result will be a map in collect.$(name) . You can also use cmerge.$(name)_str for a string version of the merged containers (if it fits in a CFEngine string). The name is variable so you can call this bundle for more than one collection. Every found variable will be a key in the map, unless you specify flatten , in which case they&#39;ll be flattened into a top-level array of data. The flatten parameter can be &quot;any&quot; or &quot;true&quot; or &quot;1&quot; to be true. Example: code body common control { inputs =&gt; { &quot; $(sys.libdir) /stdlib.cf&quot; }; } bundle agent main { vars : # the &quot;mymerge&quot; tag is user-defined &quot;a&quot; data =&gt; parsejson ( &#39; { &quot;mark&quot; : &quot;burgess&quot; } &#39; ), meta =&gt; { &quot;mymerge&quot; }; &quot;b&quot; data =&gt; parsejson ( &#39; { &quot;volker&quot; : &quot;hilsheimer&quot; } &#39; ), meta =&gt; { &quot;mymerge&quot; }; methods : # merge a, b into container collect_vars.all &quot;go&quot; usebundle =&gt; collect_vars ( &quot;all&quot; , &quot;mymerge&quot; , &quot;&quot; ); # flatten a, b into container collect_vars.flattened &quot;go_flatten&quot; usebundle =&gt; collect_vars ( &quot;flattened&quot; , &quot;mymerge&quot; , &quot;true&quot; ); reports : # merged = {&quot;default:main.a&quot;:{&quot;mark&quot;:&quot;burgess&quot;},&quot;default:main.b&quot;:{&quot;volker&quot;:&quot;hilsheimer&quot;}} &quot;merged = $(collect_vars.all_str) &quot; ; # flattened = {&quot;mark&quot;:&quot;burgess&quot;,&quot;volker&quot;:&quot;hilsheimer&quot;} &quot;flattened = $(collect_vars.flattened_str) &quot; ; } Implementation: code bundle agent collect_vars ( name , tag , flatten ) { classes : &quot;flatten&quot; expression =&gt; strcmp ( $ ( flatten ), &quot;any&quot; ); &quot;flatten&quot; expression =&gt; strcmp ( $ ( flatten ), &quot;1&quot; ); &quot;flatten&quot; expression =&gt; strcmp ( $ ( flatten ), &quot;true&quot; ); vars : &quot; todo_$(name) &quot; slist =&gt; variablesmatching ( &quot;.*&quot; , $ ( tag )); !flatten :: &quot; $(name) &quot; data =&gt; parsejson ( &#39; {} &#39; ), policy =&gt; &quot;free&quot; ; # this iterates! &quot; $(name) &quot; data =&gt; mergedata ( $ ( name ), &#39; { &quot; $(todo_$(name)) &quot; : $ ( todo_ $ ( name )) } &#39; ), policy =&gt; &quot;free&quot; ; flatten :: &quot; $(name) &quot; data =&gt; parsejson ( &#39;[]&#39; ), policy =&gt; &quot;free&quot; ; # this iterates! &quot; $(name) &quot; data =&gt; mergedata ( $ ( name ), &quot; $(todo_$(name)) &quot; ), policy =&gt; &quot;free&quot; ; any :: &quot; $(name)_str &quot; string =&gt; format ( &quot;%S&quot; , $ ( name )), policy =&gt; &quot;free&quot; ; } run_ifdefined Prototype: run_ifdefined(namespace, mybundle) Description: bundle to maybe run another bundle dynamically Arguments: namespace : the namespace, usually $(this.namespace) mybundle : the bundle to maybe run This bundle simply is a way to run another bundle only if it&#39;s defined. Example: code bundle agent run { methods : # does nothing if bundle &quot;runthis&quot; is not defined &quot;go&quot; usebundle =&gt; run_ifdefined ( $ ( this . namespace ), runthis ); } Implementation: code bundle agent run_ifdefined ( namespace , mybundle ) { vars : &quot; bundlesfound &quot; slist =&gt; bundlesmatching ( &quot;^ $(namespace) : $(mybundle) $&quot; ); &quot; count &quot; int =&gt; length ( bundlesfound ); methods : &quot;any&quot; usebundle =&gt; $ ( bundlesfound ), if =&gt; strcmp ( 1 , $ ( count )); reports : verbose_mode :: &quot; $(this.bundle) : found matching bundles $(bundlesfound) for namespace &#39; $(namespace) &#39; and bundle &#39; $(mybundle) &#39;&quot; ; }
